def is_valid_a_plus_b_star(s):
 transitions = {
 0: {'a': 1, 'b': 2},
 1: {'a': 1, 'b': 3},
 2: {'b': 2},
 3: {'b': 3}
 }
 accept_states = {1, 2, 3}
 current_state = 0

 for char in s:
 if char not in transitions[current_state]:
 return False
 current_state = transitions[current_state][char]

 return current_state in accept_states

# Example usage
print(is_valid_a_plus_b_star('aaabbb')) # True
print(is_valid_a_plus_b_star('b')) # True
print(is_valid_a_plus_b_star('ac')) # False
